command.text:
&CheckLockDateBeforeProcess;
if exists(select 1 from @@table where so_ct = @so_ct) begin select 'so_ct' as field, replace(@$exists, '%s', rtrim(@so_ct)) as message return end declare @wsID varchar(8) select @wsID = rtrim(val) from options where upper(name) = 'M_WS_ID' select @stt_rec = max(stt_rec) from kkyc select @stt_rec = @wsID + case when @stt_rec is null then '000000001' else replace(str(cast(substring(@stt_rec, 2, 9) as bigint) + 1, 9), ' ', '0') end + 'KKK'
select @datetime0 = getdate(), @datetime2 = getdate(), @user_id0 = @@userID, @user_id2 = @@userID update @kkycct set stt_rec = @stt_rec update @kkycbkk set stt_rec = @stt_rec

declare @ngay_ct smalldatetime select @ngay_ct = ngay_ct from @@table where stt_rec = @stt_rec
&CheckLockDateBeforeProcess;
declare @q nvarchar(4000), @p varchar(4), @ex char(1), @voucherNumber varchar(32), @message nvarchar(512) select @voucherNumber = so_ct from kkyc where stt_rec = @stt_rec select @message = replace(@$deleteConflict, '%s', rtrim(@voucherNumber)) &BeginCheckExists;&ContinueCheckExists;&NextCheckExists;&EndCheckExists; delete kkycct where stt_rec = @stt_rec delete kkycbkk where stt_rec = @stt_rec


var f = this, id = f.get_id(), g = f.getItem('kkycct')._controlBehavior, y = f.getItem('kkycbkk')._controlBehavior, u1 = '', u2 = '', v = f._language == 'v';
var l1 = g._getColumnOrder('ma_kho'), l2 = g._getColumnOrder('loai_vt'), l3 = g._getColumnOrder('nh_vt1'), l4 = g._getColumnOrder('nh_vt2'), l5 = g._getColumnOrder('nh_vt3');
var e1 = (v ? 'Thông tin chi tiết không được trùng nhau.' : 'Stocktaking line for item has existed.');
for (var i = 1; i < g._rowCount; i++) {
  if (!f._checked) break;
  u1 = get$CheckStringValue(g, i, l1, l2, l3, l4, l5);
  for (var j = i + 1; j <= g._rowCount; j++) {
    u2 = get$CheckStringValue(g, j, l1, l2, l3, l4, l5);
    if (u1 == u2) {
      f._errorWarningObject = g._getItem(j, l1);
      $func.hideWait(id);
      $message.show(e1, String.format('var f = $find(\'{0}\');f.focus(\'kkycct\');f._errorWarningObject.focus()', id));
      f._checked = false;
      break;
    }
  }
}
if (f._checked) {
  var c1 = g._getColumnOrder('line_nbr'), c2 = y._getColumnOrder('line_nbr');
  for (var i = 0; i < g._rowCount; i++) {
    g._setItemValue(i + 1, c1, i + 1);
  }
  for (var i = 0; i < y._rowCount; i++) {
    y._setItemValue(i + 1, c2, i + 1);
  }
}

script.text:

function active$FormStocktakingRequisition(f) {
  f.add_onResponseComplete(on$FormStocktakingRequisition$ResponseComplete);
  f.add_commandEvent(on$FormStocktakingRequisition$ExecuteCommand);
  f._tabContainer.add_activeTabChanged(onTabChanged);
  f._tabContainer._loaded = true;
  set$FormDefaultValue(f);
}
function scatter$FormStocktakingRequisition(f) {  
  f._tabContainer.add_activeTabChanged(onTabChanged);
  f._tabContainer._loaded = true;
  set$FormDefaultValue(f);
}
function close$FormStocktakingRequisition(f) {
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onTabChanged);} catch (ex) {}
  try {f.remove_commandEvent(on$FormStocktakingRequisition$ExecuteCommand);} catch (ex) {}
  try {f.remove_onResponseComplete(on$FormStocktakingRequisition$ResponseComplete)} catch (ex) {}
}
function on$FormStocktakingRequisition$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      objectBehavior$Dir$Irregular.checkCode(f, 'so_ct');
      break;
    default:
      break;
  }
}
function on$FormStocktakingRequisition$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g = f.getItem('kkycct')._controlBehavior, y = f.getItem('kkycbkk')._controlBehavior;
  switch (action) {
    case 'Gather':
      g.setSequenceNumber('line_nbr');
      g.setContinuance('stt_rec0');
      y.setSequenceNumber('line_nbr');
      y.setContinuance('stt_rec0');
      break;
    default:
      break;
  }
}
function onTabChanged(sender, e) {sender.parentForm.focusWhenTabChanged(['kkycct', 'kkycbkk']);}
function onchange$Create$Date(o) {
  var f = o.parentForm;
  f.setItemValue('ngay_ct', f.getItemValue('ngay_lct'));
  f.live(f.getItem('ngay_ct'));
}
function set$FormDefaultValue(f) {
  var g = f.getItem('kkycct')._controlBehavior;
  if (f._action == 'New') {
    var d = new Date();
    f.setItemValue('ngay_lct', d);
    f.setItemValue('ngay_ct', d);    
  }  
}
function get$CheckStringValue(g, i, l1, l2, l3, l4, l5) {
  return g._getItemValue(i, l1) + '$1' + g._getItemValue(i, l2) + '$2' + g._getItemValue(i, l3) + '$3' + g._getItemValue(i, l4) + '$4' + g._getItemValue(i, l5);
}

      &ScriptIrregular;
